import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"33. Workload","description":"","frontmatter":{"title":"33. Workload","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["hours","staffing","workload"]},"headers":[],"relativePath":"ebas/mspp/workforce-management/33-workload.md","filePath":"ebas/mspp/workforce-management/33-workload.md"}'),s={name:"ebas/mspp/workforce-management/33-workload.md"};function n(i,e,l,p,d,h){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_33-workload" tabindex="-1">33. Workload <a class="header-anchor" href="#_33-workload" aria-label="Permalink to &quot;33. Workload&quot;">​</a></h1><p><strong>a.</strong> The Employer acknowledges the benefits to both the organisation and individual Employees gained through Employees having a balance between both their professional and family life.</p><p><strong>b.</strong> The Employer further recognises that the allocation of work must include consideration of the Employee’s hours of work, health, safety and welfare.</p><p><strong>c.</strong> Work will be allocated so that an Employee does not work routinely beyond their ordinary hours of work to complete their duties, and the allocation of work does not require:</p><p><strong>(i)</strong> Working before or after rostered ordinary hours;</p><p><strong>(ii)</strong> Working through meal or rest breaks; or</p><p><strong>(iii)</strong> Undertaking work at home which is not part of an agreed work from home arrangement.</p><p><strong>d.</strong> Subject to the provisions of this Agreement, all worked performed by an Employee including time in addition to their ordinary rostered hours, shall be paid.</p><p><strong>e.</strong> In the event that particular workload or staffing issues are identified at individual health care facilities or services the Employer agrees to consult with Employees and their nominated representatives in relation to such matters.</p><p><strong>f.</strong> To inform the consultation the employer will provide relevant information that will provide clarification of the workload or staffing issues. Information that could be relevant is outlined at <a href="/eba/ebas/mspp/union-rights/17-union-rights.html">clause 17.10</a>.</p><p><strong>33.2</strong> Staffing The employer will ensure that it is sufficiently staffed and resourced so as to enable each Employee to:</p><p><strong>a.</strong> perform all aspects of their role/position during their ordinary hours;</p><p><strong>b.</strong> take rest intervals and meal breaks provided by this Agreement; and</p><p><strong>c.</strong> take leave provided for by this Agreement.</p><p><strong>33.3</strong> Allocation of work</p><p><strong>a.</strong> The Employer will allocate work to each Employee so that they can perform all aspects of their duties during their ordinary hours of work, including but not limited to:</p><p><strong>(i)</strong> clinical duties;</p><p><strong>(ii)</strong> administrative and clerical duties;</p><p><strong>(iii)</strong> managerial/supervisory duties;</p><p><strong>(iv)</strong> educational duties;</p><p><strong>(v)</strong> attending meetings; and</p><p><strong>(vi)</strong> for Psychologists, clinical supervision.</p><p><strong>b.</strong> The reference to “all aspects of their duties during their ordinary hours” in 33.3(a) excludes unpaid work such as (but not limited to):</p><p><strong>(i)</strong> additional time worked before or after rostered ordinary hours;</p><p><strong>(ii)</strong> working through meal or rest breaks;</p><p><strong>(iii)</strong> undertaking work at home which is not part of an agreed work from home arrangement.</p><p><strong>33.4</strong> Pharmacist Staffing Levels</p><p><strong>a.</strong> In setting Pharmacist staffing and workload levels the Employer will have regard to the Victorian Pharmacy Authority’s guidelines with respect to the standards of the Society of Hospital Pharmacists – Staffing Levels and Structures for the Provision of Pharmacy Services (SHPA ratios). See attached in <a href="/eba/ebas/mspp/schedules/16-shpa-ratios-pharmacist-staffing-levels.html">Schedule 16</a>.</p><p><strong>b.</strong> SHPA ratios are an agreed goal of Employers and the HSU, and action will be taken during this Agreement to commence the process of having SHPA ratios applied across Victorian public pharmacy services as soon as possible.</p><p><strong>33.5</strong> Dispute Settlement In the event of a dispute arising over the provisions of this clause, either party may choose to have the dispute resolved pursuant to the provisions of <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> – Dispute Settling Procedures or <a href="/eba/ebas/mspp/disputes/12-independent-dispute-resolution-panel.html">clause 12</a> – Independent Disputes Resolution Procedure.</p><p><strong>33.6</strong> Information – Workplace Implementation and Compliance Committee The matters in this clause are directly relevant to workload and the Employer will provide information to the Workplace Implementation and Compliance Committee as required by subclause 17.10 of this Agreement.</p><p>Plain language terms: reasonable workload, workload management.</p>',32)])])}const m=o(s,[["render",n]]);export{c as __pageData,m as default};
